SELECT 4 AS [Source Type], Item.[Model Item No_] AS [Source No_], 0 AS [Source Line No_], 10000 AS [Line No_], 2 AS [Document Type], "_" AS Description, "X:\febos\foto\" & IIf(IsNull([marchio])=False,[marchiocartella],"MARCHIO_UNK") & "\" & [season code] & "\Foto Navision\" & IIf([trademark code]="BLAUER" Or [trademark code]="BLK" Or [trademark code]="BLAC" Or [trademark code]="BEPOSITIVE" Or [trademark code]="AP" Or [trademark code]="CPH" Or [trademark code]="FOAMERS" Or [trademark code]="AQVA ALTA",UCase(SubstSlashDash([Item.model item no_]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg"),IIf([trademark code]="NAPA",SubstSlashDash([Description 2]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg",[LINE CODE] & "_" & [Model Item No_] & "_" & [Item.Variable Code 01] & "-medium.jpg")) AS [Linked Document], 0 AS Priority, 0 AS [File Not Found], "_" AS [Picture CapTion], Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01] AS [Constant Variable CodE]
FROM Item LEFT JOIN RelazioniMarchiCartelle ON Item.[Trademark Code] = RelazioniMarchiCartelle.Marchio
GROUP BY 4, Item.[Model Item No_], 10000, 2, "X:\febos\foto\" & IIf(IsNull([marchio])=False,[marchiocartella],"MARCHIO_UNK") & "\" & [season code] & "\Foto Navision\" & IIf([trademark code]="BLAUER" Or [trademark code]="BLK" Or [trademark code]="BLAC" Or [trademark code]="BEPOSITIVE" Or [trademark code]="AP" Or [trademark code]="CPH" Or [trademark code]="FOAMERS" Or [trademark code]="AQVA ALTA",UCase(SubstSlashDash([Item.model item no_]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg"),IIf([trademark code]="NAPA",SubstSlashDash([Description 2]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg",[LINE CODE] & "_" & [Model Item No_] & "_" & [Item.Variable Code 01] & "-medium.jpg")), 0, "_", Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01], 0, Item.[Configurator Relation], Item.[Trademark Code], Item.[Season Code], 0, 0, ""
HAVING (((Item.[Configurator Relation])=[Configurator relation Filter]) AND ((Item.[Trademark Code])=[forms]![principale]![filtromarchiopergeneralinks]) AND ((Item.[Season Code])=[forms]![principale]![filtrostagionepergeneralinks]));

